/* ─────────────────────────────────────────
   에디터 컨테이너
───────────────────────────────────────── */
.editor-container {
  display: flex;
  flex: 1;
  overflow: hidden;
  position: relative;
}

/* ─────────────────────────────────────────
   창 (Pane)
───────────────────────────────────────── */
.pane {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  transition: flex 0.05s;
}

.editor-pane {
  flex: 0 0 50%;
  border-right: 1px solid var(--border-subtle);
}

.preview-pane {
  flex: 1 1 0;
}

.pane-header {
  display: flex;
  align-items: center;
  height: var(--pane-header-height);
  padding: 0 16px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  flex-shrink: 0;
  user-select: none;
}

/* ─────────────────────────────────────────
   텍스트 에디터
───────────────────────────────────────── */
#editor {
  flex: 1;
  width: 100%;
  height: 100%;
  padding: 20px 24px;
  background: var(--bg-primary);
  color: var(--text-primary);
  border: none;
  outline: none;
  resize: none;
  font-family: var(--font-mono);
  font-size: 14px;
  line-height: 1.7;
  tab-size: 2;
  overflow: auto;
  caret-color: var(--accent);
}

#editor::placeholder {
  color: var(--text-muted);
}

#editor::-webkit-scrollbar {
  width: 8px;
}

#editor::-webkit-scrollbar-track {
  background: transparent;
}

#editor::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 4px;
}

#editor::-webkit-scrollbar-thumb:hover {
  background: var(--bg-hover);
}

/* ─────────────────────────────────────────
   리사이저
───────────────────────────────────────── */
.resizer {
  width: var(--resizer-width);
  background: var(--border-color);
  cursor: col-resize;
  position: relative;
  flex-shrink: 0;
  transition: background var(--transition);
  z-index: 5;
}

.resizer::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 3px;
  height: 32px;
  background: var(--text-muted);
  border-radius: 2px;
  opacity: 0;
  transition: opacity var(--transition);
}

.resizer:hover,
body.is-resizing .resizer {
  background: var(--accent);
}

.resizer:hover::after,
body.is-resizing .resizer::after {
  opacity: 0.6;
}

body.is-resizing {
  cursor: col-resize;
  user-select: none;
}

body.is-resizing * {
  pointer-events: none;
}

body.is-resizing .resizer {
  pointer-events: auto;
}

/* ─────────────────────────────────────────
   미리보기 — GitHub 마크다운 스타일
───────────────────────────────────────── */
#preview {
  flex: 1;
  overflow-y: auto;
  padding: 28px 32px;
  background: var(--bg-primary);
}

#preview::-webkit-scrollbar {
  width: 8px;
}

#preview::-webkit-scrollbar-track {
  background: transparent;
}

#preview::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 4px;
}

#preview::-webkit-scrollbar-thumb:hover {
  background: var(--bg-hover);
}

/* 마크다운 본문 스타일 */
.markdown-body {
  font-family: var(--font-ui);
  font-size: 15px;
  line-height: 1.75;
  color: var(--text-primary);
  max-width: 760px;
  word-break: break-word;
}

/* 제목 */
.markdown-body h1,
.markdown-body h2,
.markdown-body h3,
.markdown-body h4,
.markdown-body h5,
.markdown-body h6 {
  margin-top: 1.5em;
  margin-bottom: 0.5em;
  font-weight: 600;
  line-height: 1.25;
  color: var(--text-primary);
}

.markdown-body h1 {
  font-size: 2em;
  padding-bottom: 0.3em;
  border-bottom: 1px solid var(--border-color);
  margin-top: 0;
}

.markdown-body h2 {
  font-size: 1.5em;
  padding-bottom: 0.3em;
  border-bottom: 1px solid var(--border-color);
}

.markdown-body h3 { font-size: 1.25em; }
.markdown-body h4 { font-size: 1em; }
.markdown-body h5 { font-size: 0.875em; }
.markdown-body h6 { font-size: 0.85em; color: var(--text-secondary); }

/* 문단 */
.markdown-body p {
  margin: 0 0 1em;
}

/* 링크 */
.markdown-body a {
  color: var(--accent);
  text-decoration: none;
}

.markdown-body a:hover {
  text-decoration: underline;
  color: var(--accent-hover);
}

/* 이미지 */
.markdown-body img {
  max-width: 100%;
  height: auto;
  border-radius: var(--radius);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.4);
  margin: 0.5em 0;
}

/* 인라인 코드 */
.markdown-body code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  padding: 0.2em 0.45em;
  background: var(--bg-tertiary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: #f0883e;
  white-space: nowrap;
}

/* 코드 블록 */
.markdown-body .code-block {
  position: relative;
  margin: 0 0 1.25em;
  border-radius: var(--radius);
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  overflow: hidden;
}

.markdown-body .code-block[data-language]::before {
  content: attr(data-language);
  display: block;
  padding: 6px 16px 5px;
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  background: var(--bg-tertiary);
  border-bottom: 1px solid var(--border-color);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.markdown-body .code-block pre {
  margin: 0;
  padding: 16px 20px;
  overflow-x: auto;
  background: transparent;
}

.markdown-body .code-block code {
  font-family: var(--font-mono);
  font-size: 13px;
  background: transparent;
  border: none;
  padding: 0;
  color: #e6edf3;
  white-space: pre;
}

.markdown-body .code-block pre::-webkit-scrollbar {
  height: 6px;
}

.markdown-body .code-block pre::-webkit-scrollbar-track {
  background: transparent;
}

.markdown-body .code-block pre::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}

/* 인용구 */
.markdown-body blockquote {
  margin: 0 0 1em;
  padding: 4px 16px;
  border-left: 3px solid var(--border-color);
  color: var(--text-secondary);
}

.markdown-body blockquote > :last-child {
  margin-bottom: 0;
}

.markdown-body blockquote blockquote {
  margin: 0.5em 0 0.5em 0;
  border-left-color: var(--text-muted);
}

/* 목록 */
.markdown-body ul,
.markdown-body ol {
  margin: 0 0 1em;
  padding-left: 1.75em;
}

.markdown-body li {
  margin-bottom: 0.25em;
}

.markdown-body li > ul,
.markdown-body li > ol {
  margin: 0.25em 0 0;
}

.markdown-body ul {
  list-style: disc;
}

.markdown-body ul ul {
  list-style: circle;
}

.markdown-body ul ul ul {
  list-style: square;
}

.markdown-body ol {
  list-style: decimal;
}

/* 수평선 */
.markdown-body hr {
  height: 2px;
  margin: 1.5em 0;
  background: var(--border-color);
  border: none;
  border-radius: 1px;
}

/* 굵게, 기울임, 취소선 */
.markdown-body strong { font-weight: 600; color: var(--text-primary); }
.markdown-body em { font-style: italic; }
.markdown-body del { text-decoration: line-through; color: var(--text-secondary); }

/* 줄 바꿈 */
.markdown-body br { display: block; content: ''; margin-top: 0.5em; }

/* ─────────────────────────────────────────
   반응형
───────────────────────────────────────── */
@media (max-width: 768px) {
  .app-title {
    display: none;
  }

  .toolbar {
    padding: 0 10px;
    gap: 8px;
  }

  .toolbar-separator {
    margin: 0 3px;
  }

  .toolbar-btn {
    padding: 0 6px;
    height: 28px;
    min-width: 28px;
    font-size: 12px;
  }

  .export-btn {
    padding: 0 10px;
    height: 28px;
    font-size: 12px;
  }

  .editor-container {
    flex-direction: column;
  }

  .editor-pane {
    flex: 0 0 50% !important;
    border-right: none;
    border-bottom: 1px solid var(--border-subtle);
  }

  .preview-pane {
    flex: 1 1 0 !important;
  }

  .resizer {
    width: 100%;
    height: 5px;
    cursor: row-resize;
  }

  #preview {
    padding: 20px 18px;
  }
}

/* ─────────────────────────────────────────
   스크롤바 (Firefox)
───────────────────────────────────────── */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--border-color) transparent;
}

/* ─────────────────────────────────────────
   선택 색상
───────────────────────────────────────── */
::selection {
  background: var(--accent-subtle);
  color: var(--text-primary);
}

#editor::selection {
  background: rgba(88, 166, 255, 0.25);
}

