parseInline(text) {
  // 인라인 코드를 먼저 추출하고 플레이스홀더로 대체 (내부 처리 방지)
  const placeholders = [];
  text = text.replace(/`([^`]+)`/g, (_, code) => {
    const id = placeholders.length;
    placeholders.push(`<code>${this.escapeHtml(code)}</code>`);
    return `\x00${id}\x00`;
  });

  // 이스케이프 문자 처리
  text = text.replace(/\\([\\`*_{}[\]()#+\-.!])/g, (_, ch) => {
    return `&#${ch.charCodeAt(0)};`;
  });

  // 이미지 (링크보다 먼저 처리)
  text = text.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, (_, alt, src) => {
    const parts = src.match(/^(.+?)\s+"([^"]+)"$/);
    if (parts) {
      return `<img src="${this.escapeAttr(parts[1])}" alt="${this.escapeAttr(alt)}" title="${this.escapeAttr(parts[2])}">`;
    }
    return `<img src="${this.escapeAttr(src)}" alt="${this.escapeAttr(alt)}">`;
  });

  // 링크
  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, linkText, href) => {
    const parts = href.match(/^(.+?)\s+"([^"]+)"$/);
    if (parts) {
      return `<a href="${this.escapeAttr(parts[1])}" title="${this.escapeAttr(parts[2])}" target="_blank" rel="noopener noreferrer">${linkText}</a>`;
    }
    return `<a href="${this.escapeAttr(href)}" target="_blank" rel="noopener noreferrer">${linkText}</a>`;
  });

  // 자동 링크 <url>
  text = text.replace(/<(https?:\/\/[^>]+)>/g, (_, url) => {
    return `<a href="${this.escapeAttr(url)}" target="_blank" rel="noopener noreferrer">${this.escapeHtml(url)}</a>`;
  });

  // 굵게 + 기울임 (***text*** 또는 ___text___)
  text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  text = text.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');

  // 굵게 (**text** 또는 __text__)
  text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');

  // 기울임 (*text* 또는 _text_)
  text = text.replace(/\*([^*\n]+)\*/g, '<em>$1</em>');
  text = text.replace(/_([^_\n]+)_/g, '<em>$1</em>');

  // 취소선 (~~text~~)
  text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');

  // 플레이스홀더 복원
  text = text.replace(/\x00(\d+)\x00/g, (_, id) => placeholders[parseInt(id, 10)]);

  return text;
}

