    text = text.replace(/_([^_\n]+)_/g, '<em>$1</em>');

    // 10. 취소선 (~~text~~)
    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');

    // 11. 플레이스홀더 복원 (인라인 코드, 이스케이프 문자, 자동링크, 이미지, 링크)
